import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { ApiService } from '../../services/api.service';

@Component({
  selector: 'app-products',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './products.component.html',
  styleUrls: ['./products.component.scss']
})
export class ProductsComponent implements OnInit {
  products: any[] = [];
  loading = true;
  page = 1;
  limit = 12;
  total = 0;
  categories = ['Agriculture', 'Automobiles', 'Textiles', 'Industrial', 'Handicrafts'];
  selectedCategory = '';
  searchTerm = '';

  constructor(private apiService: ApiService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.route.queryParams.subscribe(params => {
      this.page = params['page'] ? parseInt(params['page']) : 1;
      this.selectedCategory = params['category'] || '';
      this.searchTerm = params['search'] || '';
      this.loadProducts();
    });
  }

  loadProducts(): void {
    this.loading = true;
    this.apiService.getProducts(this.page, this.limit, this.selectedCategory, this.searchTerm)
      .subscribe({
        next: (data) => {
          this.products = data.products;
          this.total = data.total;
          this.loading = false;
        },
        error: () => {
          this.loading = false;
        }
      });
  }

  onCategoryChange(category: string): void {
    this.selectedCategory = category;
    this.page = 1;
    this.loadProducts();
  }

  onSearch(event: any): void {
    const term = (event.target?.value || '').trim();
    this.searchTerm = term;
    this.page = 1;
    this.loadProducts();
  }

  goToPage(page: number): void {
    this.page = page;
    window.scrollTo(0, 0);
    this.loadProducts();
  }

  get totalPages(): number {
    return Math.ceil(this.total / this.limit);
  }

  get pages(): number[] {
    const arr = [];
    for (let i = 1; i <= this.totalPages; i++) {
      arr.push(i);
    }
    return arr;
  }
}
<div class="products-container">
  <div class="container">
    <h1>Our Industries</h1>

    <div class="products-wrapper">
      <div class="sidebar">
        <div class="filter-section">
          <h3>Categories</h3>
          <ul class="category-list">
            <li>
              <a (click)="onCategoryChange('')" [class.active]="!selectedCategory">
                All Categories
              </a>
            </li>
            <li *ngFor="let category of categories">
              <a (click)="onCategoryChange(category)" [class.active]="selectedCategory === category">
                {{ category }}
              </a>
            </li>
          </ul>
        </div>
      </div>

      <div class="products-content">
        <div class="search-box">
          <input 
            type="text" 
            placeholder="Search products..." 
            [value]="searchTerm"
            (input)="onSearch($event)"
          >
        </div>

        <div class="products-grid" *ngIf="!loading && products.length > 0">
          <div class="product-card" *ngFor="let product of products">
            <img [src]="product.image" [alt]="product.name" class="product-image">
            <div class="product-info">
              <h3>{{ product.name }}</h3>
              <p class="category">{{ product.category }}</p>
              <p class="description">{{ product.description }}</p>
              <div class="product-footer">
                <span class="price" *ngIf="product.price">${{ product.price }}</span>
                <button class="btn-inquiry" routerLink="/quote" [queryParams]="{ productId: product._id }">
                  Inquire Now
                </button>
              </div>
            </div>
          </div>
        </div>

        <div *ngIf="!loading && products.length === 0" class="no-products">
          <p>No products found. Try a different search or category.</p>
        </div>

        <div *ngIf="loading" class="loading">
          <p>Loading products...</p>
        </div>

        <div *ngIf="!loading && totalPages > 1" class="pagination">
          <button 
            *ngFor="let p of pages" 
            (click)="goToPage(p)" 
            [class.active]="page === p"
            class="page-btn"
          >
            {{ p }}
